import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  FaUser, 
  FaEdit, 
  FaSave, 
  FaTimes,
  FaCalendarAlt,
  FaPrescription,
  FaFileAlt,
  FaHeart,
  FaPhone,
  FaMapMarkerAlt,
  FaTint,
  FaAllergies,
  FaHistory,
  FaBirthdayCake,
  FaIdCard,
  FaUserMd,
  FaCamera,
  FaPlus,
  FaUpload,
  FaMale,
  FaFemale,
  FaRulerVertical,
  FaWeight,
  FaExclamationTriangle,
  FaUserFriends,
  FaHome,
  FaEnvelope,
  FaClipboardList
} from 'react-icons/fa';

const Profile = () => {
  const { t } = useTranslation();
  const [isEditing, setIsEditing] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');
  
  // Enhanced patient profile data
  const [profileData, setProfileData] = useState({
    // Personal Information
    name: 'Rajesh Kumar',
    age: 35,
    gender: 'Male',
    phone: '+91 98765 43210',
    email: 'rajesh.kumar@email.com',
    address: 'House No. 123, Sector 4, Chandigarh, Punjab - 160012',
    date_of_birth: '1988-03-15',
    
    // Medical Information
    blood_group: 'B+',
    height: '5\'8" (173 cm)',
    weight: '72 kg',
    allergies: 'Penicillin, Dust, Pollen',
    current_conditions: 'Hypertension, Type 2 Diabetes',
    
    // Emergency Contact
    emergency_contact_name: 'Sunita Kumar',
    emergency_contact_relation: 'Wife',
    emergency_contact_phone: '+91 87654 32109',
    
    // Profile Picture
    avatar: null
  });

  // Dummy recent appointments
  const recentAppointments = [
    {
      id: 'APT001',
      doctor: 'Dr. Priya Sharma',
      specialty: 'Cardiology',
      date: '2024-01-15',
      time: '10:30 AM',
      status: 'Completed',
      diagnosis: 'Regular checkup - Normal'
    },
    {
      id: 'APT002', 
      doctor: 'Dr. Harpreet Singh',
      specialty: 'General Medicine',
      date: '2024-01-08',
      time: '02:00 PM',
      status: 'Completed',
      diagnosis: 'Fever, prescribed medication'
    },
    {
      id: 'APT003',
      doctor: 'Dr. Sunita Devi',
      specialty: 'Dermatology',
      date: '2024-01-20',
      time: '11:00 AM',
      status: 'Upcoming',
      diagnosis: 'Scheduled'
    }
  ];

  // Dummy medical conditions
  const medicalConditions = [
    {
      condition: 'Hypertension',
      diagnosed: '2020-06-15',
      status: 'Managed',
      medication: 'Amlodipine 5mg daily'
    },
    {
      condition: 'Type 2 Diabetes',
      diagnosed: '2019-11-20',
      status: 'Controlled',
      medication: 'Metformin 500mg twice daily'
    }
  ];

  const handleSave = () => {
    setIsEditing(false);
    // In a real app, this would save to the backend
    console.log('Profile saved:', profileData);
  };

  const handleAvatarChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setProfileData(prev => ({
          ...prev,
          avatar: e.target.result
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  // Patient Header Component
  const PatientHeader = () => (
    <div className="relative bg-gradient-to-r from-blue-600 to-purple-600 rounded-t-xl p-6 text-white">
      {/* Background Pattern */}
      <div className="absolute inset-0 bg-black bg-opacity-10 rounded-t-xl"></div>
      
      <div className="relative flex items-center space-x-4">
        {/* Avatar Section */}
        <div className="relative">
          <div className="w-20 h-20 rounded-full bg-white bg-opacity-20 flex items-center justify-center overflow-hidden border-4 border-white border-opacity-30">
            {profileData.avatar ? (
              <img 
                src={profileData.avatar} 
                alt="Profile" 
                className="w-full h-full object-cover"
              />
            ) : (
              <FaUser className="text-3xl text-white" />
            )}
          </div>
          
          {/* Camera Icon for Avatar Upload */}
          <button 
            className="absolute -bottom-1 -right-1 w-7 h-7 bg-blue-500 rounded-full flex items-center justify-center shadow-lg hover:bg-blue-600 transition-colors"
            onClick={() => document.getElementById('avatar-upload').click()}
          >
            <FaCamera className="text-xs text-white" />
          </button>
          <input
            type="file"
            id="avatar-upload"
            accept="image/*"
            onChange={handleAvatarChange}
            className="hidden"
          />
        </div>

        {/* Patient Info */}
        <div className="flex-1">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold">{profileData.name}</h1>
              <div className="flex items-center space-x-4 mt-1 text-blue-100">
                <span className="flex items-center space-x-1">
                  <FaBirthdayCake className="text-sm" />
                  <span>Age {profileData.age}</span>
                </span>
                <span className="flex items-center space-x-1">
                  {profileData.gender === 'Male' ? 
                    <FaMale className="text-sm" /> : 
                    <FaFemale className="text-sm" />
                  }
                  <span>{profileData.gender}</span>
                </span>
              </div>
            </div>
            
            {/* Edit Button */}
            <button
              onClick={() => setIsEditing(!isEditing)}
              className="bg-white bg-opacity-20 hover:bg-opacity-30 transition-all duration-200 px-4 py-2 rounded-lg flex items-center space-x-2 backdrop-blur-sm"
            >
              {isEditing ? <FaTimes className="text-sm" /> : <FaEdit className="text-sm" />}
              <span className="text-sm font-medium">
                {isEditing ? 'Cancel' : 'Edit Profile'}
              </span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  // Modern Tab Navigation
  const TabNavigation = () => (
    <div className="bg-white border-b border-gray-200 px-6">
      <div className="flex space-x-8">
        <button
          onClick={() => setActiveTab('profile')}
          className={`py-4 px-2 border-b-2 font-semibold text-sm transition-colors duration-200 ${
            activeTab === 'profile'
              ? 'border-blue-500 text-blue-600'
              : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          <div className="flex items-center space-x-2">
            <FaUser className="text-sm" />
            <span>Profile Information</span>
          </div>
        </button>
        <button
          onClick={() => setActiveTab('appointments')}
          className={`py-4 px-2 border-b-2 font-semibold text-sm transition-colors duration-200 ${
            activeTab === 'appointments'
              ? 'border-blue-500 text-blue-600'
              : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          <div className="flex items-center space-x-2">
            <FaCalendarAlt className="text-sm" />
            <span>Appointment History</span>
          </div>
        </button>
      </div>
    </div>
  );

  // Information Field Component
  const InfoField = ({ icon: Icon, label, value, name, type = "text", editable = true }) => (
    <div className="space-y-2">
      <label className="flex items-center space-x-2 text-sm font-medium text-gray-700">
        <Icon className="text-blue-500 text-sm" />
        <span>{label}</span>
      </label>
      {isEditing && editable ? (
        <input
          type={type}
          name={name}
          value={value}
          onChange={handleInputChange}
          className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200"
        />
      ) : (
        <div className="px-4 py-3 bg-gray-50 rounded-lg text-gray-900 min-h-[48px] flex items-center">
          {value || 'Not specified'}
        </div>
      )}
    </div>
  );

  // Personal Information Section
  const PersonalInformationCard = () => (
    <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
      <div className="bg-gradient-to-r from-blue-50 to-indigo-50 px-6 py-4 border-b border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800 flex items-center space-x-2">
          <FaUser className="text-blue-600" />
          <span>Personal Information</span>
        </h3>
      </div>
      
      <div className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <InfoField
            icon={FaUser}
            label="Full Name"
            value={profileData.name}
            name="name"
          />
          <InfoField
            icon={FaBirthdayCake}
            label="Age"
            value={profileData.age}
            name="age"
            type="number"
          />
          <InfoField
            icon={profileData.gender === 'Male' ? FaMale : FaFemale}
            label="Gender"
            value={profileData.gender}
            name="gender"
          />
          <InfoField
            icon={FaPhone}
            label="Contact Number"
            value={profileData.phone}
            name="phone"
            type="tel"
          />
          <InfoField
            icon={FaEnvelope}
            label="Email Address"
            value={profileData.email}
            name="email"
            type="email"
          />
          <InfoField
            icon={FaCalendarAlt}
            label="Date of Birth"
            value={profileData.date_of_birth}
            name="date_of_birth"
            type="date"
          />
        </div>
        
        <div className="mt-6">
          <InfoField
            icon={FaMapMarkerAlt}
            label="Address"
            value={profileData.address}
            name="address"
          />
        </div>
      </div>
    </div>
  );

  // Medical Information Section
  const MedicalInformationCard = () => (
    <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
      <div className="bg-gradient-to-r from-red-50 to-pink-50 px-6 py-4 border-b border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800 flex items-center space-x-2">
          <FaHeart className="text-red-600" />
          <span>Medical Information</span>
        </h3>
      </div>
      
      <div className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <InfoField
            icon={FaTint}
            label="Blood Group"
            value={profileData.blood_group}
            name="blood_group"
          />
          <InfoField
            icon={FaRulerVertical}
            label="Height"
            value={profileData.height}
            name="height"
          />
          <InfoField
            icon={FaWeight}
            label="Weight"
            value={profileData.weight}
            name="weight"
          />
          <InfoField
            icon={FaAllergies}
            label="Known Allergies"
            value={profileData.allergies}
            name="allergies"
          />
        </div>
        
        <div className="mt-6">
          <InfoField
            icon={FaExclamationTriangle}
            label="Current Medical Conditions"
            value={profileData.current_conditions}
            name="current_conditions"
          />
        </div>
      </div>
    </div>
  );

  // Emergency Contact Section
  const EmergencyContactCard = () => (
    <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
      <div className="bg-gradient-to-r from-orange-50 to-yellow-50 px-6 py-4 border-b border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800 flex items-center space-x-2">
          <FaUserFriends className="text-orange-600" />
          <span>Emergency Contact</span>
        </h3>
      </div>
      
      <div className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <InfoField
            icon={FaUser}
            label="Contact Name"
            value={profileData.emergency_contact_name}
            name="emergency_contact_name"
          />
          <InfoField
            icon={FaUserFriends}
            label="Relationship"
            value={profileData.emergency_contact_relation}
            name="emergency_contact_relation"
          />
          <InfoField
            icon={FaPhone}
            label="Phone Number"
            value={profileData.emergency_contact_phone}
            name="emergency_contact_phone"
            type="tel"
          />
        </div>
      </div>
    </div>
  );

  const renderProfileTab = () => (
    <div className="space-y-6">
      {/* Personal Information Card */}
      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-xl font-bold text-text-primary flex items-center gap-2">
            <FaUser className="text-primary-color" />
            Personal Information
          </h3>
          <button
            onClick={() => setIsEditing(!isEditing)}
            className={`btn ${
              isEditing 
                ? 'btn-secondary' 
                : 'btn-primary'
            }`}
          >
            {isEditing ? <FaTimes /> : <FaEdit />}
            {isEditing ? 'Cancel' : 'Edit'}
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="input-group">
            <label className="block text-sm font-semibold text-text-primary mb-2">
              <FaUser className="inline mr-2 text-primary-color" />
              Full Name
            </label>
            {isEditing ? (
              <input
                type="text"
                name="name"
                value={profileData.name}
                onChange={handleInputChange}
                className="input"
              />
            ) : (
              <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">{profileData.name}</p>
            )}
          </div>

          <div className="input-group">
            <label className="block text-sm font-semibold text-text-primary mb-2">
              <FaBirthdayCake className="inline mr-2 text-primary-color" />
              Age
            </label>
            {isEditing ? (
              <input
                type="number"
                name="age"
                value={profileData.age}
                onChange={handleInputChange}
                className="input"
              />
            ) : (
              <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">{profileData.age} years</p>
            )}
          </div>

          <div className="input-group">
            <label className="block text-sm font-semibold text-text-primary mb-2">
              <FaIdCard className="inline mr-2 text-primary-color" />
              Gender
            </label>
            {isEditing ? (
              <select
                name="gender"
                value={profileData.gender}
                onChange={handleInputChange}
                className="input"
              >
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>
            ) : (
              <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">{profileData.gender}</p>
            )}
          </div>

          <div className="input-group">
            <label className="block text-sm font-semibold text-text-primary mb-2">
              <FaPhone className="inline mr-2 text-primary-color" />
              Contact Number
            </label>
            {isEditing ? (
              <input
                type="tel"
                name="phone"
                value={profileData.phone}
                onChange={handleInputChange}
                className="input"
              />
            ) : (
              <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">{profileData.phone}</p>
            )}
          </div>

          <div className="md:col-span-2 input-group">
            <label className="block text-sm font-semibold text-text-primary mb-2">
              <FaMapMarkerAlt className="inline mr-2 text-primary-color" />
              Address
            </label>
            {isEditing ? (
              <textarea
                name="address"
                value={profileData.address}
                onChange={handleInputChange}
                rows="3"
                className="input resize-none"
              />
            ) : (
              <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">{profileData.address}</p>
            )}
          </div>
        </div>

        {isEditing && (
          <div className="mt-6 text-right">
            <button
              onClick={handleSave}
              className="btn btn-success"
            >
              <FaSave />
              Save Changes
            </button>
          </div>
        )}
      </div>

      {/* Medical Information Card */}
      <div className="card">
        <h3 className="text-xl font-bold text-text-primary mb-6 flex items-center gap-2">
          <FaHeart className="text-red-500" />
          Medical Information
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div>
            <label className="block text-sm font-semibold text-text-primary mb-2">
              <FaTint className="inline mr-2 text-red-600" />
              Blood Group
            </label>
            <p className="text-text-primary bg-red-50 px-4 py-3 rounded-lg text-center font-bold">{profileData.blood_group}</p>
          </div>

          <div>
            <label className="block text-sm font-semibold text-text-primary mb-2">Height</label>
            <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">{profileData.height}</p>
          </div>

          <div>
            <label className="block text-sm font-semibold text-text-primary mb-2">Weight</label>
            <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">{profileData.weight}</p>
          </div>

          <div>
            <label className="block text-sm font-semibold text-text-primary mb-2">Insurance</label>
            <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg text-sm">{profileData.insurance_number}</p>
          </div>
        </div>

        <div className="mt-6 space-y-4">
          <div>
            <label className="block text-sm font-semibold text-text-primary mb-2">
              <FaAllergies className="inline mr-2 text-orange-600" />
              Known Allergies
            </label>
            <p className="text-text-primary bg-orange-50 px-4 py-3 rounded-lg">{profileData.allergies}</p>
          </div>

          <div>
            <label className="block text-sm font-semibold text-text-primary mb-2">Emergency Contact</label>
            <p className="text-text-primary bg-bg-secondary px-4 py-3 rounded-lg">
              {profileData.emergency_contact_name} - {profileData.emergency_contact}
            </p>
          </div>
        </div>
      </div>

      {/* Current Medical Conditions */}
      <div className="card">
        <h3 className="text-xl font-bold text-text-primary mb-6 flex items-center gap-2">
          <FaFileAlt className="text-primary-color" />
          Current Medical Conditions
        </h3>

        <div className="space-y-4">
          {medicalConditions.map((condition, index) => (
            <div key={index} className="border border-border-light rounded-lg p-4">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div>
                  <p className="text-sm font-semibold text-text-secondary">Condition</p>
                  <p className="text-text-primary font-medium">{condition.condition}</p>
                </div>
                <div>
                  <p className="text-sm font-semibold text-text-secondary">Diagnosed</p>
                  <p className="text-text-primary">{condition.diagnosed}</p>
                </div>
                <div>
                  <p className="text-sm font-semibold text-text-secondary">Status</p>
                  <span className={`inline-block px-2 py-1 rounded-full text-xs font-semibold ${
                    condition.status === 'Controlled' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
                  }`}>
                    {condition.status}
                  </span>
                </div>
                <div>
                  <p className="text-sm font-semibold text-text-secondary">Current Medication</p>
                  <p className="text-text-primary text-sm">{condition.medication}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  const renderAppointmentsTab = () => (
    <div className="card">
      <h3 className="text-xl font-bold text-text-primary mb-6 flex items-center gap-2">
        <FaCalendarAlt className="text-primary-color" />
        Recent Appointments
      </h3>

      <div className="space-y-4">
        {recentAppointments.map((appointment) => (
          <div key={appointment.id} className="border border-border-light rounded-lg p-4 hover:shadow-md transition-shadow">
            <div className="grid grid-cols-1 md:grid-cols-5 gap-4 items-center">
              <div>
                <p className="text-sm font-semibold text-text-secondary">Doctor</p>
                <p className="text-text-primary font-medium">{appointment.doctor}</p>
                <p className="text-primary-color text-sm">{appointment.specialty}</p>
              </div>
              <div>
                <p className="text-sm font-semibold text-text-secondary">Date</p>
                <p className="text-text-primary">{appointment.date}</p>
              </div>
              <div>
                <p className="text-sm font-semibold text-text-secondary">Time</p>
                <p className="text-text-primary">{appointment.time}</p>
              </div>
              <div>
                <p className="text-sm font-semibold text-text-secondary">Status</p>
                <span className={`inline-block px-2 py-1 rounded-full text-xs font-semibold ${
                  appointment.status === 'Completed' 
                    ? 'bg-green-100 text-green-800' 
                    : appointment.status === 'Upcoming'
                    ? 'bg-blue-100 text-blue-800'
                    : 'bg-gray-100 text-gray-800'
                }`}>
                  {appointment.status}
                </span>
              </div>
              <div>
                <p className="text-sm font-semibold text-text-secondary">Notes</p>
                <p className="text-text-primary text-sm">{appointment.diagnosis}</p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-bg-secondary">
      {/* Professional Header with Helio Branding */}
      <div className="bg-gradient-to-r from-primary-color to-primary-dark text-white py-12">
        <div className="container mx-auto px-6">
          <div className="flex items-center gap-6">
            <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center text-primary-color text-3xl font-bold">
              {profileData.name.split(' ').map(n => n[0]).join('')}
            </div>
            <div>
              <h1 className="text-4xl font-black mb-2 tracking-tight">
                Patient Profile - <span className="text-primary-light">Helio</span>
              </h1>
              <p className="text-xl text-primary-light font-medium">
                {profileData.name} • Age {profileData.age} • {profileData.gender}
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-6 py-8 pb-32">
        <div className="max-w-6xl mx-auto">
          {/* Tab Navigation */}
          <div className="card mb-8">
            <div className="flex border-b border-border-light">
              <button
                onClick={() => setActiveTab('profile')}
                className={`px-6 py-4 font-semibold transition-colors focus-ring ${
                  activeTab === 'profile'
                    ? 'text-primary-color border-b-2 border-primary-color'
                    : 'text-text-secondary hover:text-primary-color'
                }`}
              >
                Profile Information
              </button>
              <button
                onClick={() => setActiveTab('appointments')}
                className={`px-6 py-4 font-semibold transition-colors focus-ring ${
                  activeTab === 'appointments'
                    ? 'text-primary-color border-b-2 border-primary-color'
                    : 'text-text-secondary hover:text-primary-color'
                }`}
              >
                Appointment History
              </button>
            </div>
          </div>

          {/* Tab Content */}
          {activeTab === 'profile' && renderProfileTab()}
          {activeTab === 'appointments' && renderAppointmentsTab()}
        </div>
      </div>
    </div>
  );
};

export default Profile;
